+function cosineSimilaritySIMD(a, b) {
+  let dotProduct = 0;
+  let magA = 0;
+  let magB = 0;
+  for (let i = 0; i < a.length; i++) {
+    dotProduct += a[i] * b[i];
+    magA += a[i] * a[i];
+    magB += b[i] * b[i];
+  }
+  return dotProduct / (Math.sqrt(magA) * Math.sqrt(magB));
