+      dot1 += a[i + 1] * b[i + 1];
+      dot2 += a[i + 2] * b[i + 2];
+      dot3 += a[i + 3] * b[i + 3];
+
+      magA0 += a[i] * a[i];
+      magA1 += a[i + 1] * a[i + 1];
+      magA2 += a[i + 2] * a[i + 2];
+      magA3 += a[i + 3] * a[i + 3];
+
+      magB0 += b[i] * b[i];
+      magB1 += b[i + 1] * b[i + 1];
+      magB2 += b[i + 2] * b[i + 2];
+      magB3 += b[i + 3] * b[i + 3];
+    }
+
+    let dot = dot0 + dot1 + dot2 + dot3;
