+
+    const child = spawn('node', [demo.script], {
+      stdio: 'inherit',
+      cwd: process.cwd()
+    });
+
+    child.on('close', (code) => {
+      if (code === 0) {
+        console.log(`\n✅ ${demo.name} completed successfully\n`);
